#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

int countAssignments(int* seats, int n) {
    int* dp = (int*)malloc(n * sizeof(int));
    dp[0] = 1;
    for (int i = 1; i < n; i++) {
        dp[i] = (dp[i-1] * 2) % MOD;
    }
    int result = 0;
    for (int mask = 0; mask < (1 << n); mask++) {
        int valid = 1;
        int* assigned = (int*)malloc(n * sizeof(int));
        for (int i = 0; i < n; i++) {
            assigned[i] = 0;
        }
        for (int i = 0; i < n; i++) {
            if ((mask & (1 << i)) != 0) {
                if (assigned[seats[i] - 1] == 0) {
                    assigned[seats[i] - 1] = 1;
                } else {
                    valid = 0;
                    break;
                }
            }
        }
        if (valid) {
            result = (result + dp[n-1]) % MOD;
        }
        free(assigned);
    }
    free(dp);
    return result;
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n;
        scanf("%d", &n);
        int* seats = (int*)malloc(n * sizeof(int));
        for (int i = 0; i < n; i++) {
            scanf("%d", &seats[i]);
        }
        printf("%d\n", countAssignments(seats, n));
        free(seats);
    }
    return 0;
}

